package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.COMMENT;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.SP;
import java.io.Closeable;
import java.io.Flushable;
import java.sql.ResultSet;
import java.sql.SQLException;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVPrinterTest {

    private CSVPrinter csvPrinter;
    private Appendable out;
    private CSVFormat format;

    @BeforeEach
    void setUp() {
        out = mock(Appendable.class);
        format = mock(CSVFormat.class);
        csvPrinter = new CSVPrinter(out, format);
    }

    private void invokePrint(Object object, CharSequence value, int offset, int len) throws Throwable {
        Method method = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        method.setAccessible(true);
        try {
            method.invoke(csvPrinter, object, value, offset, len);
        } catch (InvocationTargetException e) {
            throw e.getCause();
        }
    }

    private void stubPrivateVoidMethod(Object spy, String methodName, Class<?>[] paramTypes, Object[] args) throws Exception {
        Method method = CSVPrinter.class.getDeclaredMethod(methodName, paramTypes);
        method.setAccessible(true);
        doAnswer(invocation -> null).when(spy, methodName, args);
    }

    private void doNothingPrivateMethod(Object spy, String methodName, Class<?>[] paramTypes) throws Exception {
        Method method = CSVPrinter.class.getDeclaredMethod(methodName, paramTypes);
        method.setAccessible(true);
        // Use Mockito's doAnswer with reflection proxy
        doAnswer(invocation -> null).when(spy, methodName, any(), any(), anyInt(), anyInt());
    }

    private void doNothingPrivateMethod(Object spy, String methodName, Class<?>[] paramTypes, Object[] anyMatchers) throws Exception {
        Method method = CSVPrinter.class.getDeclaredMethod(methodName, paramTypes);
        method.setAccessible(true);
        // Cannot directly do doNothing().when(spy).privateMethod() due to private access
        // So use Mockito's spy + reflection + doAnswer workaround below
    }

    private void doNothingPrivateMethod(Object spy, String methodName, Class<?>[] paramTypes, Object... anyMatchers) throws Exception {
        Method method = CSVPrinter.class.getDeclaredMethod(methodName, paramTypes);
        method.setAccessible(true);
        // Mockito cannot mock private methods by name, so we use spy + reflection + doAnswer
        // But Mockito does not support mocking private methods directly
        // So we will suppress the private method by overriding via reflection proxy or use a workaround:
        // Instead, we will replace the private method with a public wrapper for testing only or skip verifying private method calls
        // The best way: invoke print method and verify expected behavior on Appendable and state, skip verifying private method calls
    }

    @Test
    void testPrint_NewRecordTrue_QuoteCharacterSet() throws Throwable {
        when(format.isQuoteCharacterSet()).thenReturn(true);
        when(format.isEscapeCharacterSet()).thenReturn(false);
        when(format.getDelimiter()).thenReturn(',');

        setNewRecord(csvPrinter, true);

        // We cannot mock private methods directly; instead, invoke print and verify effects
        CSVPrinter spyPrinter = Mockito.spy(csvPrinter);

        // Suppress printAndQuote by reflection: replace with no-op using Proxy or use partial mocking
        // Here, we invoke print method and verify that out.append(delimiter) is NOT called because newRecord is true
        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);

        // Instead of mocking private printAndQuote, we can invoke print and verify out append calls
        printMethod.invoke(spyPrinter, "obj", "value", 0, 5);

        // verify delimiter NOT appended because newRecord is true
        verify(out, never()).append(',');

        // We cannot verify private method call printAndQuote, so skip it

        // The test is still valid by verifying output and state
    }

    @Test
    void testPrint_NewRecordFalse_QuoteCharacterSet() throws Throwable {
        when(format.isQuoteCharacterSet()).thenReturn(true);
        when(format.isEscapeCharacterSet()).thenReturn(false);
        when(format.getDelimiter()).thenReturn(';');

        setNewRecord(csvPrinter, false);

        CSVPrinter spyPrinter = Mockito.spy(csvPrinter);

        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);
        printMethod.invoke(spyPrinter, "obj", "val", 0, 3);

        verify(out).append(';');

        // Cannot verify private method printAndQuote call; skip

        assertFalse(getNewRecord(spyPrinter));
    }

    @Test
    void testPrint_EscapeCharacterSet() throws Throwable {
        when(format.isQuoteCharacterSet()).thenReturn(false);
        when(format.isEscapeCharacterSet()).thenReturn(true);
        when(format.getDelimiter()).thenReturn('|');

        setNewRecord(csvPrinter, false);

        CSVPrinter spyPrinter = Mockito.spy(csvPrinter);

        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);
        printMethod.invoke(spyPrinter, null, "abcdef", 1, 4);

        verify(out).append('|');

        // Cannot verify private method printAndEscape call; skip

        assertFalse(getNewRecord(spyPrinter));
    }

    @Test
    void testPrint_NoQuoteNoEscape() throws Throwable {
        when(format.isQuoteCharacterSet()).thenReturn(false);
        when(format.isEscapeCharacterSet()).thenReturn(false);
        when(format.getDelimiter()).thenReturn('\t');

        setNewRecord(csvPrinter, false);

        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);
        printMethod.invoke(csvPrinter, null, "0123456789", 2, 4);

        verify(out).append('\t');
        verify(out).append("0123456789", 2, 6);
        assertFalse(getNewRecord(csvPrinter));
    }

    private void setNewRecord(CSVPrinter printer, boolean value) throws Exception {
        Field field = CSVPrinter.class.getDeclaredField("newRecord");
        field.setAccessible(true);
        field.set(printer, value);
    }

    private boolean getNewRecord(CSVPrinter printer) throws Exception {
        Field field = CSVPrinter.class.getDeclaredField("newRecord");
        field.setAccessible(true);
        return (boolean) field.get(printer);
    }
}
